      WHEN NULLIF(BTRIM(LOWER(email_address)), '') IS NULL THEN NULL
      WHEN LOWER(BTRIM(email_address)) LIKE '%noemail@%' THEN NULL
      WHEN LOWER(BTRIM(email_address)) LIKE '%x@gmail%' THEN NULL
      WHEN LOWER(BTRIM(email_address)) LIKE '%kersten@master%' THEN NULL
      WHEN LOWER(BTRIM(email_address)) LIKE '%nizarabd@hotmail%' THEN NULL
      WHEN LOWER(BTRIM(email_address)) LIKE '%noemail@telus%' THEN NULL
      WHEN LOWER(BTRIM(email_address)) LIKE '%noemail@gmail%' THEN NULL
      WHEN LOWER(BTRIM(email_address)) LIKE '%x.@gmail%' THEN NULL
      WHEN LOWER(BTRIM(email_address)) !~ '^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}$' THEN NULL
      ELSE LOWER(BTRIM(email_address))
    END AS email,
    CASE
      WHEN LENGTH(REGEXP_REPLACE(COALESCE(phone_number, ''), '\D', '', 'g')) = 11
        AND REGEXP_REPLACE(COALESCE(phone_number, ''), '\D', '', 'g') LIKE '1%'
        THEN SUBSTRING(REGEXP_REPLACE(COALESCE(phone_number, ''), '\D', '', 'g') FROM 2)
      WHEN LENGTH(REGEXP_REPLACE(COALESCE(phone_number, ''), '\D', '', 'g')) BETWEEN 7 AND 11
        THEN REGEXP_REPLACE(COALESCE(phone_number, ''), '\D', '', 'g')
      WHEN LENGTH(REGEXP_REPLACE(COALESCE(reference_id, ''), '\D', '', 'g')) = 11
        AND REGEXP_REPLACE(COALESCE(reference_id, ''), '\D', '', 'g') LIKE '1%'
        THEN SUBSTRING(REGEXP_REPLACE(COALESCE(reference_id, ''), '\D', '', 'g') FROM 2)
      WHEN LENGTH(REGEXP_REPLACE(COALESCE(reference_id, ''), '\D', '', 'g')) BETWEEN 7 AND 11
        THEN REGEXP_REPLACE(COALESCE(reference_id, ''), '\D', '', 'g')
      ELSE NULL
    END AS phone,
    COALESCE(
      NULLIF(BTRIM(CONCAT_WS(' ', NULLIF(street_address_1, ''), NULLIF(street_address_2, ''))), ''),
      NULLIF(BTRIM(state), '')
    ) AS address,
    NULLIF(BTRIM(city), '') AS city,
    UPPER(NULLIF(BTRIM(postal_code), '')) AS postal_code,
    CASE
      WHEN NULLIF(BTRIM(birthday), '') ~ '^\d{4}-\d{2}-\d{2}$' THEN NULLIF(BTRIM(birthday), '')::date
      ELSE NULL
    END AS birthday,
    NULLIF(BTRIM(square_customer_id), '') AS square_customer_id,
    NULLIF(BTRIM(reference_id), '') AS external_reference
  FROM raw_contacts
), filtered AS (
  SELECT *
  FROM normalized
  WHERE NOT (first_name = 'PIX' AND last_name = 'PIX')
    AND NOT (first_name = 'x' AND last_name = 'x')
    AND COALESCE(first_name, '') NOT LIKE 'xxx%'
    AND COALESCE(phone, '') <> '1111111111'
    AND NOT (first_name IS NULL AND last_name IS NULL)
), unique_contacts AS (
  SELECT *
  FROM (
    SELECT
      f.*,
      ROW_NUMBER() OVER (PARTITION BY phone ORDER BY csv_row) AS phone_rank,
      ROW_NUMBER() OVER (PARTITION BY email ORDER BY csv_row) AS email_rank
    FROM filtered f
  ) ranked
  WHERE (phone IS NULL OR phone_rank = 1)
    AND (email IS NULL OR email_rank = 1)
), to_insert AS (
  SELECT u.*
  FROM unique_contacts u
  WHERE NOT EXISTS (
    SELECT 1 FROM public.crm_contacts c
    WHERE u.phone IS NOT NULL
      AND REGEXP_REPLACE(COALESCE(c.phone, ''), '\D', '', 'g') = u.phone
  )
  AND NOT EXISTS (
    SELECT 1 FROM public.crm_contacts c
    WHERE u.email IS NOT NULL
      AND LOWER(c.email) = u.email
  )
)
INSERT INTO public.crm_contacts (
  full_name,
  first_name,
  last_name,
  email,
  phone,
  address,
  city,
  postal_code,
  birthday,
  square_customer_id,
  external_reference,
  source,
  call_status,
  priority,
  status,
  tags,
  notes
)
SELECT
  BTRIM(CONCAT_WS(' ', first_name, last_name)) AS full_name,
  first_name,
  last_name,
  email,
  phone,
  address,
  city,
  postal_code,
  birthday,
  square_customer_id,
  external_reference,
  'shopify_import',
  'not_called',
  2,
  'lead',
  ARRAY['shopify_import'],
  'One-time direct Shopify/Square CSV import, row ' || csv_row::text
FROM to_insert
WHERE BTRIM(CONCAT_WS(' ', first_name, last_name)) <> '';
